# infra/config.py
import os

_defaults = {
    'redis_host': 'localhost',
    'redis_port': 6379,
    'redis_db': 0,
    'session_ttl_seconds': 1800,  # 30 minutes
    'session_prefix': 'hb:session:',
    'max_sessions_per_user': 3,
}


def get_config() -> dict:
    """Return application config, with environment variable overrides."""
    config = dict(_defaults)
    if os.environ.get('REDIS_HOST'):
        config['redis_host'] = os.environ['REDIS_HOST']
    if os.environ.get('REDIS_PORT'):
        config['redis_port'] = int(os.environ['REDIS_PORT'])
    if os.environ.get('SESSION_TTL'):
        config['session_ttl_seconds'] = int(os.environ['SESSION_TTL'])
    return config

