import pytest
import time
import json
from unittest.mock import patch, MagicMock
from auth.session import SessionManager
from infra.config import get_config


@pytest.fixture
def mock_redis():
    """Create a mock Redis client that simulates basic Redis operations."""
    store = {}
    ttls = {}

    mock = MagicMock()

    def setex(key, ttl, value):
        store[key] = value
        ttls[key] = ttl
        return True

    def get(key):
        return store.get(key)

    def delete(*keys):
        count = 0
        for key in keys:
            if key in store:
                del store[key]
                if key in ttls:
                    del ttls[key]
                count += 1
        return count

    def exists(key):
        return 1 if key in store else 0

    def keys(pattern):
        import fnmatch
        return [k for k in store.keys() if fnmatch.fnmatch(k, pattern)]

    def ttl(key):
        if key in ttls:
            return ttls[key]
        return -2

    mock.setex = MagicMock(side_effect=setex)
    mock.get = MagicMock(side_effect=get)
    mock.delete = MagicMock(side_effect=delete)
    mock.exists = MagicMock(side_effect=exists)
    mock.keys = MagicMock(side_effect=keys)
    mock.ttl = MagicMock(side_effect=ttl)
    mock._store = store
    mock._ttls = ttls

    return mock


@pytest.fixture
def session_manager(mock_redis):
    with patch('auth.session.get_redis_client', return_value=mock_redis):
        manager = SessionManager()
    return manager


class TestSessionTokenGeneration:
    def test_token_is_hex_string(self, session_manager):
        token = session_manager._generate_session_token()
        assert isinstance(token, str)
        # Should be valid hex
        int(token, 16)

    def test_token_length(self, session_manager):
        token = session_manager._generate_session_token()
        # Should be at least 64 hex characters (32 bytes)
        assert len(token) >= 64

    def test_tokens_are_unique(self, session_manager):
        tokens = set()
        for _ in range(100):
            token = session_manager._generate_session_token()
            tokens.add(token)
        # All 100 tokens should be unique
        assert len(tokens) == 100

    def test_token_is_not_predictable(self, session_manager):
        """Tokens generated in quick succession should not be sequential or predictable."""
        tokens = [session_manager._generate_session_token() for _ in range(10)]
        # Check that consecutive tokens don't share long common prefixes
        for i in range(len(tokens) - 1):
            common_prefix_len = 0
            for a, b in zip(tokens[i], tokens[i+1]):
                if a == b:
                    common_prefix_len += 1
                else:
                    break
            # Cryptographically random tokens should rarely share >8 char prefixes
            assert common_prefix_len < 16, "Tokens appear to be sequential or predictable"


class TestSessionCreation:
    def test_create_session_returns_token(self, session_manager, mock_redis):
        user_data = {'user_id': 'user_123', 'username': 'patient1', 'role': 'patient'}
        token = session_manager.create_session(user_data)
        assert isinstance(token, str)
        assert len(token) >= 64

    def test_create_session_stores_in_redis(self, session_manager, mock_redis):
        user_data = {'user_id': 'user_123', 'username': 'patient1', 'role': 'patient'}
        token = session_manager.create_session(user_data)

        config = get_config()
        expected_key = f"{config['session_prefix']}{token}"
        assert expected_key in mock_redis._store

    def test_create_session_stores_user_data(self, session_manager, mock_redis):
        user_data = {'user_id': 'user_123', 'username': 'patient1', 'role': 'patient'}
        token = session_manager.create_session(user_data)

        config = get_config()
        stored = json.loads(mock_redis._store[f"{config['session_prefix']}{token}"])
        assert stored['user_id'] == 'user_123'
        assert stored['username'] == 'patient1'

    def test_create_session_sets_ttl(self, session_manager, mock_redis):
        user_data = {'user_id': 'user_123', 'username': 'patient1', 'role': 'patient'}
        token = session_manager.create_session(user_data)

        config = get_config()
        expected_key = f"{config['session_prefix']}{token}"
        assert mock_redis._ttls[expected_key] == config['session_ttl_seconds']


class TestSessionValidation:
    def test_validate_existing_session(self, session_manager, mock_redis):
        user_data = {'user_id': 'user_123', 'username': 'patient1', 'role': 'patient'}
        token = session_manager.create_session(user_data)

        session = session_manager.validate_session(token)
        assert session is not None
        assert session['user_id'] == 'user_123'

    def test_validate_nonexistent_session(self, session_manager):
        session = session_manager.validate_session('nonexistent_token_abc123')
        assert session is None

    def test_validate_empty_token(self, session_manager):
        session = session_manager.validate_session('')
        assert session is None

    def test_validate_none_token(self, session_manager):
        session = session_manager.validate_session(None)
        assert session is None


class TestSessionDestruction:
    def test_destroy_session(self, session_manager, mock_redis):
        user_data = {'user_id': 'user_123', 'username': 'patient1', 'role': 'patient'}
        token = session_manager.create_session(user_data)

        result = session_manager.destroy_session(token)
        assert result is True

        # Session should no longer be valid
        session = session_manager.validate_session(token)
        assert session is None

    def test_destroy_nonexistent_session(self, session_manager):
        result = session_manager.destroy_session('nonexistent_token')
        assert result is False


class TestSessionSecurity:
    def test_token_uses_cryptographic_randomness(self, session_manager):
        """Verify that token generation uses the secrets module (CSPRNG)."""
        with patch('auth.session.secrets') as mock_secrets:
            mock_secrets.token_hex.return_value = 'a' * 64
            token = session_manager._generate_session_token()
            mock_secrets.token_hex.assert_called_once_with(32)
            assert token == 'a' * 64

