import pytest
from unittest.mock import patch, MagicMock
from auth.login import authenticate_user


@pytest.fixture
def mock_user():
    user = MagicMock()
    user.verify_password.return_value = True
    user.to_dict.return_value = {
        'user_id': 'user_123',
        'username': 'testpatient',
        'role': 'patient',
        'email': 'patient@example.com'
    }
    return user


class TestAuthentication:
    @patch('auth.login.User')
    def test_successful_login(self, MockUser, mock_user):
        MockUser.find_by_username.return_value = mock_user
        result = authenticate_user('testpatient', 'correctpassword')
        assert result is not None
        assert result['username'] == 'testpatient'

    @patch('auth.login.User')
    def test_failed_login_wrong_password(self, MockUser, mock_user):
        mock_user.verify_password.return_value = False
        MockUser.find_by_username.return_value = mock_user
        result = authenticate_user('testpatient', 'wrongpassword')
        assert result is None

    @patch('auth.login.User')
    def test_failed_login_unknown_user(self, MockUser):
        MockUser.find_by_username.return_value = None
        result = authenticate_user('unknown', 'password')
        assert result is None
